import React, { memo } from "react";

function Table({ columns, data, onRowClick, emptyMessage = "Sin datos", className = "" }) {
  return (
    <div className={`overflow-x-auto rounded-xl border border-gray-200 ${className}`}>
      <table className="w-full text-sm text-left">
        <thead className="bg-gray-50 border-b border-gray-200">
          <tr>
            {columns.map((col) => (
              <th
                key={col.key}
                onClick={col.onSort}
                className={`px-4 py-3 text-xs font-semibold text-gray-500 uppercase tracking-wide whitespace-nowrap
                  ${col.onSort ? "cursor-pointer hover:text-gray-700 select-none" : ""}
                  ${col.className || ""}`}
                aria-sort={col.sortDir}
              >
                <span className="flex items-center gap-1">
                  {col.label}
                  {col.onSort && (
                    <span className="text-gray-300 text-xs">
                      {col.sortDir === "asc" ? "▲" : col.sortDir === "desc" ? "▼" : "⇅"}
                    </span>
                  )}
                </span>
              </th>
            ))}
          </tr>
        </thead>
        <tbody className="divide-y divide-gray-100">
          {data.length === 0 ? (
            <tr>
              <td colSpan={columns.length} className="px-4 py-10 text-center text-gray-400 text-sm">
                {emptyMessage}
              </td>
            </tr>
          ) : (
            data.map((row, i) => (
              <tr
                key={row.id ?? i}
                onClick={() => onRowClick?.(row)}
                className={`transition-colors duration-100
                  ${onRowClick ? "cursor-pointer" : ""}
                  hover:bg-gray-50`}
              >
                {columns.map((col) => (
                  <td key={col.key} className={`px-4 py-3 ${col.cellClass || ""}`}>
                    {col.render ? col.render(row) : row[col.key]}
                  </td>
                ))}
              </tr>
            ))
          )}
        </tbody>
      </table>
    </div>
  );
}

export default memo(Table);
